import React, { useState } from "react";

function ScreenerPage() {
  const [peBelow, setPeBelow] = useState("");
  const [marketCapAbove, setMarketCapAbove] = useState("");
  const [results, setResults] = useState([]);
  const [loading, setLoading] = useState(false);

  const handleSearch = async () => {
    let url = "http://localhost:3000/api/screener";

    const params = [];
    if (peBelow) params.push(`peBelow=${peBelow}`);
    if (marketCapAbove) params.push(`marketCapAbove=${marketCapAbove}`);
    if (params.length > 0) url += "?" + params.join("&");

    setLoading(true);
    try {
      const res = await fetch(url);
      const data = await res.json();
      setResults(data.results || []);
    } catch (error) {
      console.error(error);
      alert("Error fetching screener data.");
    }
    setLoading(false);
  };

  return (
    <div style={{ maxWidth: "1000px", margin: "0 auto", padding: "2rem" }}>
      <h2 style={{ textAlign: "center", marginBottom: "1.5rem" }}>
        Stock Screener
      </h2>

      <div style={{ display: "flex", gap: "1rem", marginBottom: "2rem" }}>
        <input
          type="number"
          placeholder="PE Ratio below..."
          value={peBelow}
          onChange={(e) => setPeBelow(e.target.value)}
          style={{
            flex: 1,
            padding: "0.8rem",
            border: "1px solid #ccc",
            borderRadius: "5px",
            fontSize: "1rem",
          }}
        />
        <input
          type="number"
          placeholder="Market Cap above (₹)"
          value={marketCapAbove}
          onChange={(e) => setMarketCapAbove(e.target.value)}
          style={{
            flex: 1,
            padding: "0.8rem",
            border: "1px solid #ccc",
            borderRadius: "5px",
            fontSize: "1rem",
          }}
        />
        <button
          onClick={handleSearch}
          style={{
            backgroundColor: "#007bff",
            color: "#fff",
            border: "none",
            padding: "0.8rem 1.5rem",
            borderRadius: "5px",
            cursor: "pointer",
            fontWeight: "bold",
            transition: "all 0.3s",
          }}
          onMouseEnter={(e) => {
            e.target.style.backgroundColor = "#0056b3";
          }}
          onMouseLeave={(e) => {
            e.target.style.backgroundColor = "#007bff";
          }}
        >
          {loading ? "Loading..." : "Screen"}
        </button>
      </div>

      {results.length > 0 && (
        <table
          style={{
            width: "100%",
            borderCollapse: "collapse",
            marginTop: "1rem",
          }}
        >
          <thead style={{ background: "#007bff", color: "#fff" }}>
            <tr>
              <th style={{ padding: "10px", textAlign: "left" }}>Symbol</th>
              <th style={{ padding: "10px", textAlign: "left" }}>Name</th>
              <th style={{ padding: "10px", textAlign: "left" }}>Price</th>
              <th style={{ padding: "10px", textAlign: "left" }}>PE Ratio</th>
              <th style={{ padding: "10px", textAlign: "left" }}>
                Market Cap (₹)
              </th>
              <th style={{ padding: "10px", textAlign: "left" }}>
                Dividend Yield
              </th>
              <th style={{ padding: "10px", textAlign: "left" }}>52W High</th>
              <th style={{ padding: "10px", textAlign: "left" }}>52W Low</th>
            </tr>
          </thead>
          <tbody>
            {results.map((stock, index) => (
              <tr
                key={index}
                style={{
                  backgroundColor:
                    index % 2 === 0 ? "#f9f9f9" : "transparent",
                }}
              >
                <td style={{ padding: "10px" }}>{stock.symbol}</td>
                <td style={{ padding: "10px" }}>{stock.name}</td>
                <td style={{ padding: "10px" }}>{stock.price}</td>
                <td style={{ padding: "10px" }}>{stock.pe}</td>
                <td style={{ padding: "10px" }}>
                  {stock.marketCap
                    ? (stock.marketCap / 1e7).toFixed(2) + " Cr"
                    : "N/A"}
                </td>
                <td style={{ padding: "10px" }}>
                  {stock.dividendYield !== null
                    ? (stock.dividendYield * 100).toFixed(2) + "%"
                    : "N/A"}
                </td>
                <td style={{ padding: "10px" }}>
                  {stock.fiftyTwoWeekHigh}
                </td>
                <td style={{ padding: "10px" }}>
                  {stock.fiftyTwoWeekLow}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}

      {!loading && results.length === 0 && (
        <p style={{ textAlign: "center", marginTop: "2rem" }}>
          No results yet. Enter filters and search.
        </p>
      )}
    </div>
  );
}

export default ScreenerPage;
